sys_ui_action.script:
(function executeAction(current, previous /*null when async*/ ) {

    // Create record in target custom table
    var grTargetRecord = new GlideRecord('x_451445_wrm_workspace_maintenance');
    grTargetRecord.initialize();

    // Set field values
    grTargetRecord.ticket_status = 'open'; // Use correct choice value
    grTargetRecord.workspace_status = 'in_maintenance';
    grTargetRecord.date_reported = new GlideDateTime();
	grTargetRecord.reservation = current.sys_id;
	grTargetRecord.workspace = current.workspace;
	grTargetRecord.issue_description = current.close_notes;
    grTargetRecord.assignment_group = '8ddd3a2bc308cf100ccab1fdd4013133';

    // Insert record
    var newRecordSysId = grTargetRecord.insert();

    // Optional: Info message
    if (newRecordSysId) {
        if (grTargetRecord.get(newRecordSysId)) {

            var recordNumber = grTargetRecord.getValue('number');

          gs.addInfoMessage('Created record on Workspace Maintainance : ' + recordNumber);
        }
    }

		action.setRedirectURL(current);

    // Optional: Redirect to new record
    //action.setRedirectURL(grTargetRecord);


})(current, previous);
